let damageCost = 0;
let potentialSavings = 0;

// Step 1: Base damage factors based on weather conditions
// Coefficients are empirical and aim to reflect relative damage potential.
const baseSnowFactor = Math.min(0.00008 * inputs.maxStormSnowfall + 0.00004 * inputs.avgAnnualSnowfall, 0.015); // Cap snow factor at 1.5% for extreme values
const baseIceFactor = Math.min(0.008 * inputs.maxIceAccumulation, 0.04); // Ice is extremely damaging, cap at 4%
const baseWindFactor = Math.min(0.000008 * Math.pow(inputs.maxStormWindGusts, 1.8), 0.03); // Wind damage increases non-linearly, cap at 3%

let weatherDamageFactor = baseSnowFactor + baseIceFactor + baseWindFactor;

// Step 2: Structural vulnerability multipliers
let vulnerabilityMultiplier = 1.0;

// Roof Age: Older roofs are significantly more vulnerable to snow, ice, and wind.
if (inputs.roofAge > 30) {
    vulnerabilityMultiplier *= 1.5; // Very old roof, high risk
} else if (inputs.roofAge > 20) {
    vulnerabilityMultiplier *= 1.3; // Older roof
} else if (inputs.roofAge > 10) {
    vulnerabilityMultiplier *= 1.1; // Moderately aged roof
}
// Cap roof age multiplier to prevent extreme values
vulnerabilityMultiplier = Math.min(vulnerabilityMultiplier, 2.5);

// Foundation Type: Basements and crawl spaces are more prone to water damage from snowmelt and heavy rains.
if (inputs.foundationType === 'Basement') {
    vulnerabilityMultiplier *= 1.18; // Higher risk for water damage, foundation cracks
} else if (inputs.foundationType === 'Crawl Space') {
    vulnerabilityMultiplier *= 1.10; // Moderate risk for water damage, freezing pipes
}
// Slab foundations generally have lower risk of flood damage from ground level, but not zero.

// Tree Exposure: Proximity to large trees increases risk of damage from falling branches/trees due to ice and wind.
if (inputs.treeExposure === 'High') {
    vulnerabilityMultiplier *= 1.35; // Significant risk from falling branches/trees
} else if (inputs.treeExposure === 'Moderate') {
    vulnerabilityMultiplier *= 1.15; // Moderate risk
}

// Total estimated damage percentage for an unprotected property
let estimatedDamagePercentage = weatherDamageFactor * vulnerabilityMultiplier;

// Cap total damage percentage to a reasonable maximum for a single event (e.g., 25% of property value)
estimatedDamagePercentage = Math.min(estimatedDamagePercentage, 0.25);

damageCost = inputs.propertyValue * estimatedDamagePercentage;
damageCost = Math.round(damageCost); // Round to nearest dollar

// Step 3: Preventative measures savings and net cost calculation
let costOfPrevention = (inputs.hasPreventativeMeasures === 'Yes' && inputs.costPreventativeMeasures !== null) ? inputs.costPreventativeMeasures : 0;
let netCostWithPrevention = damageCost + costOfPrevention; // Default: damage + prevention cost if no savings

if (inputs.hasPreventativeMeasures === 'Yes') {
    // Preventative measures like tree trimming, roof inspection, gutter cleaning, sealing, insulation
    // are estimated to reduce potential damage by a significant factor.
    const preventionEfficiencyFactor = 0.35; // Empirical estimate: 35% reduction in potential damage
    potentialSavings = damageCost * preventionEfficiencyFactor;
    potentialSavings = Math.round(potentialSavings); // Round savings

    netCostWithPrevention = damageCost - potentialSavings + costOfPrevention;
    netCostWithPrevention = Math.max(0, netCostWithPrevention); // Net cost cannot be negative
    netCostWithPrevention = Math.round(netCostWithPrevention);
} else {
    // If no preventative measures, there are no savings and prevention cost is 0
    potentialSavings = 0;
    costOfPrevention = 0; // Explicitly ensure 0 if 'No' selected, even if a value was typed in.
    netCostWithPrevention = damageCost;
}

// Ensure all outputs are non-negative
damageCost = Math.max(0, damageCost);
potentialSavings = Math.max(0, potentialSavings);
netCostWithPrevention = Math.max(0, netCostWithPrevention);

return {
    estimatedDamageCost: damageCost,
    potentialSavings: potentialSavings,
    netCostWithPrevention: netCostWithPrevention
};
